INSERT INTO public.oq_daily_qt (qt_date, bible_book, chapter, verse_from, verse_to, content)
VALUES
  ('2026-03-01', '사무엘하', 9, 6, 11, '6. 사울의 손자 요나단의 아들 므비보셋이 다윗에게 나아와 그 앞에 엎드려 절하매 다윗이 이르되 므비보셋이여 하니 그가 이르되 보소서 당신의 종이니이다\n7. 다윗이 그에게 이르되 무서워하지 말라 내가 반드시 네 아버지 요나단으로 말미암아 네게 은총을 베풀리라 내가 네 할아버지 사울의 모든 밭을 다 네게 도로 주겠고 또 너는 항상 내 상에서 떡을 먹을지니라 하니\n8. 그가 절하여 이르되 이 종이 무엇이기에 왕께서 죽은 개 같은 나를 돌아보시나이까 하니라\n9. 왕이 사울의 사환 시바를 불러 그에게 이르되 사울과 그의 온 집에 속한 것은 내가 다 네 주인의 아들에게 주었노니\n10. 너와 네 아들들과 네 종들은 그를 위하여 땅을 갈고 거두어 네 주인의 아들에게 양식을 대어 먹게 하라 그러나 네 주인의 아들 므비보셋은 항상 내 상에서 떡을 먹으리라 하니라 시바는 아들이 열다섯 명이요 종이 스무 명이라\n11. 시바가 왕께 아뢰되 내 주 왕께서 모든 일을 종에게 명령하신 대로 종이 준행하겠나이다 하니라 므비보셋은 왕자 중 하나처럼 왕의 상에서 먹으니라'),
  ('2026-03-02', '사무엘하', 11, 1, 5, '1. 그 해가 돌아와 왕들이 출전할 때가 되매 다윗이 요압과 그에게 있는 그의 부하들과 온 이스라엘 군대를 보내니 그들이 암몬 자손을 멸하고 랍바를 에워싸고 다윗은 예루살렘에 그대로 있더라\n2. 저녁 때에 다윗이 그의 침상에서 일어나 왕궁 옥상에서 거닐다가 그 곳에서 보니 한 여인이 목욕을 하는데 심히 아름다워 보이는지라\n3. 다윗이 사람을 보내 그 여인을 알아보게 하였더니 그가 아뢰되 그는 엘리암의 딸이요 헷 사람 우리아의 아내 밧세바가 아니니이까 하니\n4. 다윗이 전령을 보내어 그 여자를 자기에게로 데려오게 하고 그 여자가 그 부정함을 깨끗하게 하였으므로 더불어 동침하매 그 여자가 자기 집으로 돌아가니라\n5. 그 여인이 임신하매 사람을 보내 다윗에게 말하여 이르되 내가 임신하였나이다 하니라'),
  ('2026-03-03', '사무엘하', 11, 6, 13, '6. 다윗이 요압에게 기별하여 헷 사람 우리아를 내게 보내라 하매 요압이 우리아를 다윗에게로 보내니\n7. 우리아가 다윗에게 이르매 다윗이 요압의 안부와 군사의 안부와 싸움이 어떠했는지를 묻고 그가 또 우리아에게 이르되 네 집으로 내려가서 발을 씻으라 하니 우리아가 왕궁에서 나가매 왕의 음식물이 뒤따라 가니라\n8. 그러나 우리아는 집으로 내려가지 아니하고 왕궁 문에서 그의 주의 모든 부하들과 더불어 잔지라\n9. 어떤 사람이 다윗에게 아뢰되 우리아가 그의 집으로 내려가지 아니하였나이다 다윗이 우리아에게 이르되 네가 길 갔다가 돌아온 것이 아니냐 어찌하여 네 집으로 내려가지 아니하였느냐 하니\n10. 우리아가 다윗에게 아뢰되 언약궤와 이스라엘과 유다가 야영 중에 있고 내 주 요압과 내 왕의 부하들이 바깥 들에 진 치고 있거늘 내가 어찌 내 집으로 가서 먹고 마시고 내 처와 같이 자리이까 내가 이 일을 행하지 아니하기로 왕의 살아 계심과 왕의 혼의 살아 계심을 두고 맹세하나이다 하니라\n11. 다윗이 우리아에게 이르되 오늘도 여기 있으라 내일은 내가 너를 보내리라 우리아가 그 날에 예루살렘에 머무니라\n12. 이튿날 다윗이 그를 불러서 그로 그 앞에서 먹고 마시고 취하게 하니 저녁 때에 그가 나가서 그의 주의 부하들과 더불어 침상에 눕고 그의 집으로 내려가지 아니하니라\n13. 아침이 되매 다윗이 편지를 써서 우리아의 손에 들려 요압에게 보내니'),
  ('2026-03-04', '사무엘하', 11, 14, 21, '14. 아침이 되매 다윗이 편지를 써서 우리아의 손에 들려 요압에게 보내니\n15. 그 편지에 써서 이르기를 너희가 우리아를 맹렬한 싸움에 앞세워 두고 너희는 뒤로 물러가서 그로 맞아 죽게 하라 하였더라\n16. 요압이 그 성을 살필 때에 용사들이 있는 것을 아는 그 곳에 우리아를 두니\n17. 그 성 사람들이 나와서 요압과 더불어 싸울 때에 다윗의 부하 중 몇 사람이 엎드러지고 헷 사람 우리아도 죽으니라\n18. 요압이 사람을 보내 그 전쟁의 모든 일을 다윗에게 보고할새\n19. 그 전령에게 명령하여 이르되 전쟁의 모든 일을 네가 왕께 보고하기를 마친 후에\n20. 혹시 왕이 노하여 네게 말씀하기를 너희가 어찌하여 성에 그토록 가까이 가서 싸웠느냐 그들이 성 위에서 쏠 줄을 알지 못하였느냐\n21. 여룹베셋의 아들 아비멜렉을 쳐죽인 자가 누구냐 여인 하나가 성 위에서 맷돌 윗짝을 그 위에 던지매 그가 데벳스에서 죽지 아니하였느냐 어찌하여 성에 가까이 갔더냐 하시거든 네가 말하기를 왕의 종 헷 사람 우리아도 죽었나이다 하라'),
  ('2026-03-05', '사무엘하', 11, 22, 27, '22. 전령이 가서 다윗에게 이르러 요압이 보낸 모든 일을 아뢰어\n23. 이르되 그 사람들이 우리보다 우세하여 들로 우리를 나오고 우리가 그들을 쳐서 성문 어귀까지 갔더니\n24. 활 쏘는 자들이 성 위에서 왕의 부하들을 향하여 쏘매 왕의 부하 중 몇 사람이 죽고 왕의 종 헷 사람 우리아도 죽었나이다 하니\n25. 다윗이 전령에게 이르되 너는 요압에게 이같이 말하기를 이 일로 걱정하지 말라 칼은 이 사람이나 저 사람이나 삼키느니라 그 성을 향하여 더욱 힘써 싸워 함락시키라 하여 너는 그를 담대하게 하라 하니라\n26. 우리아의 아내는 그 남편 우리아가 죽었음을 듣고 그의 남편을 위하여 울리라\n27. 그 장례를 마치매 다윗이 사람을 보내 그를 왕궁으로 데려오니 그가 그의 아내가 되어 그에게 아들을 낳으니라 다윗이 행한 그 일이 여호와 보시기에 악하였더라'),
  ('2026-03-06', '사무엘하', 12, 1, 6, '1. 여호와께서 나단을 다윗에게 보내시니 그가 다윗에게 가서 그에게 이르되 한 성읍에 두 사람이 있는데 한 사람은 부하고 한 사람은 가난하니\n2. 그 부한 사람은 양과 소가 심히 많으나\n3. 가난한 사람은 아무것도 없고 자기가 사서 기르는 작은 암양 새끼 한 마리뿐이라 그 암양 새끼는 그와 그의 자식과 함께 있어 자라며 그가 먹는 것을 먹으며 그의 잔으로 마시며 그의 품에 누우므로 그에게는 딸처럼 되었거늘\n4. 어떤 행인이 그 부자에게 오매 부자가 자기에게 온 행인을 위하여 자기의 양과 소를 아껴 잡지 아니하고 가난한 사람의 양 새끼를 빼앗아다가 자기에게 온 사람을 위하여 잡았나이다 하니\n5. 다윗이 그 사람으로 말미암아 노하여 나단에게 이르되 여호와의 살아 계심을 두고 맹세하노니 이 일을 행한 그 사람은 마땅히 죽을 자라\n6. 그가 불쌍히 여기지 아니하고 이런 일을 행하였으니 그 양 새끼를 네 배나 갚아 주어야 하리라 한지라'),
  ('2026-03-07', '사무엘하', 12, 7, 14, '7. 나단이 다윗에게 이르되 당신이 그 사람이라 이스라엘의 하나님 여호와께서 이같이 이르시기를 내가 너를 이스라엘 왕으로 기름 붓기 위하여 너를 사울의 손에서 구원하고\n8. 네 주인의 집을 네게 주고 네 주인의 아내들을 네 품에 두고 이스라엘과 유다 족속을 네게 맡겼느니라 만일 그것이 부족하였을 것 같으면 내가 네게 이것 저것을 더 주었으리라\n9. 그러한데 어찌하여 네가 여호와의 말씀을 업신여기고 나 보기에 악을 행하였느냐 네가 칼로 헷 사람 우리아를 치되 암몬 자손의 칼로 죽이고 그의 아내를 빼앗아 네 아내로 삼았도다\n10. 이제 네가 나를 업신여기고 헷 사람 우리아의 아내를 빼앗아 네 아내로 삼았은즉 칼이 네 집에서 영원토록 떠나지 아니하리라 하셨고\n11. 여호와께서 또 이와 같이 이르시기를 보라 내가 너와 네 집에 재앙을 일으키고 내가 네 눈앞에서 네 아내를 빼앗아 네 이웃들에게 주리니 그 사람들이 네 아내들과 더불어 백주에 동침하리라\n12. 너는 은밀히 행하였으나 나는 온 이스라엘 앞에서 백주에 이 일을 행하리라 하셨나이다 하니\n13. 다윗이 나단에게 이르되 내가 여호와께 죄를 범하였노라 하매 나단이 다윗에게 말하되 여호와께서도 당신의 죄를 사하셨나니 당신이 죽지 아니하려니와\n14. 이 일로 말미암아 여호와의 원수가 크게 비방할 거리를 얻게 하였으니 당신이 낳은 아이가 반드시 죽으리이다 하고'),
  ('2026-03-08', '사무엘하', 11, 7, 11, '7. 우리아가 다윗에게 이르매 다윗이 요압의 안부와 군사의 안부와 싸움이 어떠했는지를 묻고\n8. 그가 또 우리아에게 이르되 네 집으로 내려가서 발을 씻으라 하니 우리아가 왕궁에서 나가매 왕의 음식물이 뒤따라 가니라\n9. 그러나 우리아는 집으로 내려가지 아니하고 왕궁 문에서 그의 주의 모든 부하들과 더불어 잔지라\n10. 어떤 사람이 다윗에게 아뢰되 우리아가 그의 집으로 내려가지 아니하였나이다 다윗이 우리아에게 이르되 네가 길 갔다가 돌아온 것이 아니냐 어찌하여 네 집으로 내려가지 아니하였느냐 하니\n11. 우리아가 다윗에게 아뢰되 언약궤와 이스라엘과 유다가 야영 중에 있고 내 주 요압과 내 왕의 부하들이 바깥 들에 진 치고 있거늘 내가 어찌 내 집으로 가서 먹고 마시고 내 처와 같이 자리이까 내가 이 일을 행하지 아니하기로 왕의 살아 계심과 왕의 혼의 살아 계심을 두고 맹세하나이다 하니라'),
  ('2026-03-09', '사무엘하', 12, 15, 23, '15. 나단이 자기 집으로 돌아가니라 우리아의 아내가 다윗에게 낳은 아이를 여호와께서 치시매 심히 앓는지라\n16. 다윗이 그 아이를 위하여 하나님께 간구하되 다윗이 금식하고 안에 들어가서 밤새도록 땅에 엎드렸으니\n17. 그 집의 늙은 자들이 그 곁에 서서 다윗을 땅에서 일으키려 하되 왕이 듣지 아니하고 그들과 더불어 먹지도 아니하더라\n18. 이레 만에 그 아이가 죽으니라 그러나 다윗의 신하들이 아이가 죽은 것을 왕에게 아뢰기를 두려워하니 이는 그들이 말하기를 아이가 살았을 때에 우리가 그에게 말하여도 왕이 그 말을 듣지 아니하셨나니 어떻게 그 아이가 죽은 것을 그에게 아뢸 수 있으랴 왕이 상심하시리로다 함이라\n19. 다윗이 그의 신하들이 서로 수군거리는 것을 보고 그 아이가 죽은 줄을 다윗이 깨닫고 그의 신하들에게 묻되 아이가 죽었느냐 하니 대답하되 죽었나이다 하는지라\n20. 다윗이 땅에서 일어나 몸을 씻고 기름을 바르고 의복을 갈아입고 여호와의 전에 들어가서 경배하고 왕궁으로 돌아와 명령하여 음식을 그 앞에 차리게 하고 먹은지라\n21. 그의 신하들이 그에게 이르되 아이가 살았을 때에는 그를 위하여 금식하고 우시더니 죽은 후에는 일어나서 잡수시니 이 일이 어찌 됨이니이까 하니\n22. 이르되 아이가 살았을 때에 내가 금식하고 운 것은 혹시 여호와께서 나를 불쌍히 여기사 아이를 살려 주실는지 누가 알까 생각함이거니와\n23. 지금은 죽었으니 내가 어찌 금식하랴 내가 다시 돌아오게 할 수 있느냐 나는 그에게로 가려니와 그는 내게로 돌아오지 아니하리라 하니라'),
  ('2026-03-10', '사무엘하', 12, 24, 31, '24. 다윗이 그의 아내 밧세바를 위로하고 그에게 들어가 그와 동침하였더니 그가 아들을 낳으매 그의 이름을 솔로몬이라 하니라 여호와께서 그를 사랑하사\n25. 선지자 나단을 보내 그의 이름을 여디디야라 하시니 이는 여호와께서 사랑하셨기 때문이더라\n26. 요압이 암몬 자손의 랍바를 쳐서 그 왕성을 함락시키매\n27. 요압이 전령을 다윗에게 보내 이르되 내가 랍바 곧 물들의 성읍을 쳐서 함락시켰으니\n28. 이제 왕은 그 백성의 남은 군사를 모아 그 성에 맞서 진 치고 이 성읍을 쳐서 함락시키소서 내가 이 성읍을 함락시키면 이 성읍이 내 이름으로 일컬음을 받을까 두려워하나이다 하니\n29. 다윗이 모든 백성을 모아 랍바로 가서 그 곳을 쳐서 함락시키고\n30. 그 왕의 머리에서 보석 박힌 왕관을 가져오니 그 중량이 금 한 달란트라 다윗이 자기의 머리에 쓰니라 다윗이 또 그 성읍에서 노략한 물건을 무수히 내오고\n31. 그 안에 있는 백성들을 끌어내어 톱질과 써레질과 철도끼질과 벽돌 구이를 그들에게 하게 하니라 암몬 자손의 모든 성읍을 이같이 하고 다윗과 모든 백성이 예루살렘으로 돌아가니라'),
  ('2026-03-11', '사무엘하', 13, 1, 6, '1. 그 후에 이 일이 있으니라 다윗의 아들 압살롬에게 아름다운 누이가 있으니 이름은 다말이라 다윗의 다른 아들 암논이 그를 사랑하나\n2. 그는 처녀이므로 어찌할 수 없는 줄을 알고 암논이 그의 누이 다말 때문에 울화로 말미암아 병이 되니라\n3. 암논에게 요나답이라 하는 친구가 있으니 그는 다윗의 형 시므아의 아들이요 심히 간교한 자라\n4. 그가 암논에게 이르되 왕자여 당신은 어찌하여 나날이 이렇게 파리하여 가느냐 내게 말해 주지 아니하겠느냐 하니 암논이 말하되 내가 아우 압살롬의 누이 다말을 사랑함이니라 하니라\n5. 요나답이 그에게 이르되 침상에 누워 병든 체하다가 네 아버지가 너를 보러 오거든 너는 그에게 말하기를 청하건대 내 누이 다말이 와서 내게 음식을 먹이되 내가 보는 데에서 음식을 차려 그의 손으로 먹여 주게 하옵소서 하라 하니\n6. 암논이 곧 누워 병든 체하다가 왕이 그를 보러 오매 암논이 왕께 아뢰되 청하건대 내 누이 다말이 와서 내가 보는 데에서 과자 두어 개를 만들어 그의 손으로 내게 먹여 주게 하옵소서 하니'),
  ('2026-03-12', '사무엘하', 13, 7, 14, '7. 다윗이 사람을 그의 집으로 보내 다말에게 이르되 이제 네 오라버니 암논의 집으로 가서 그를 위하여 음식을 차리라 한지라\n8. 다말이 그 오라버니 암논의 집으로 가매 그가 누웠더라 다말이 밀가루를 가지고 반죽하여 그가 보는 데서 과자를 만들고 그 과자를 굽고\n9. 그 냄비를 가져다가 그 앞에 쏟아 놓아도 암논이 먹기를 거절하고 암논이 이르되 모든 사람을 내게서 나가게 하라 하니 다 그를 떠나 나가니라\n10. 암논이 다말에게 이르되 음식물을 가지고 침실로 들어오라 내가 네 손에서 먹으리라 하니 다말이 자기가 만든 과자를 가지고 침실에 들어가 그의 오라버니 암논에게 이르러\n11. 그에게 먹이려고 가까이 갈 때에 암논이 그를 붙잡고 그에게 이르되 나의 누이야 와서 나와 동침하자 하는지라\n12. 그가 그에게 대답하되 아니라 내 오라버니여 나를 욕되게 하지 말라 이런 일은 이스라엘에서 마땅히 행하지 못할 것이니 이 어리석은 일을 행하지 말라\n13. 내가 이 수치를 무릅쓰고 어디로 가겠느냐 너도 이스라엘에서 어리석은 자 중 하나가 되리라 이제 청하건대 왕께 말하라 그가 나를 네게 주기를 거절하지 아니하시리라 하되\n14. 암논이 그 말을 듣지 아니하고 다말보다 힘이 세므로 억지로 그와 동침하니라'),
  ('2026-03-13', '사무엘하', 13, 15, 22, '15. 그리하고 암논이 그를 심히 미워하니 이제 미워하는 마음이 전에 사랑하던 사랑보다 더한지라 암논이 그에게 이르되 일어나 가라 하니\n16. 다말이 그에게 이르되 옳지 아니하다 나를 쫓아내는 이 큰 악은 아까 내게 행한 그 악보다 더하다 하되 암논이 그를 듣지 아니하고\n17. 그가 부리는 종을 불러 이르되 이 계집을 내게서 내보내고 곧 빗장을 지르라 하니\n18. 암논의 하인이 그를 끌어내고 곧 빗장을 지르니라 다말이 채색옷을 입었으니 출가하지 아니한 공주들은 이런 옷으로 단장하는 법이라\n19. 다말이 재를 자기의 머리에 덮어쓰고 그의 채색옷을 찢고 손을 머리 위에 얹고 가서 크게 울부짖으니라\n20. 그의 오라버니 압살롬이 그에게 이르되 네 오라버니 암논이 너와 함께 있었느냐 그러나 그는 네 오라버니이니 누이야 지금은 잠잠히 있고 이것으로 말미암아 근심하지 말라 하니라 이에 다말이 그의 오라버니 압살롬의 집에 있어 처량하게 지내니라\n21. 다윗 왕이 이 모든 일을 듣고 심히 노하니라\n22. 압살롬은 암논이 그의 누이 다말을 욕되게 하였으므로 그를 미워하여 암논에 대하여 잘잘못을 압살롬이 말하지 아니하니라'),
  ('2026-03-14', '사무엘하', 13, 23, 29, '23. 이 년 후에 에브라임 곁 바알하솔에서 압살롬이 양 털을 깎는 일이 있으매 압살롬이 왕의 모든 아들을 청하고\n24. 압살롬이 왕에게 나아가 말하되 이제 종에게 양 털 깎는 일이 있사오니 청건대 왕은 신하들을 데리시고 이 종과 함께 가사이다 하니\n25. 왕이 압살롬에게 이르되 아니라 내 아들아 이제 우리가 다 갈 것 없다 네게 폐를 끼칠까 하노라 하니라 압살롬이 그에게 간청하되 그가 가지 아니하고 그에게 복을 빌어 주는지라\n26. 압살롬이 이르되 그렇게 하지 아니하시려거든 청건대 내 형 암논이 우리와 함께 가게 하옵소서 왕이 그에게 이르되 그가 너와 함께 갈 것이 무엇이냐 하되\n27. 압살롬이 간청하매 왕이 암논과 왕의 모든 아들을 그와 함께 보내니라\n28. 압살롬이 이미 그의 종들에게 명령하여 이르기를 너희는 이제 암논의 마음이 술로 즐거워할 때를 자세히 보다가 내가 너희에게 암논을 치라 하거든 그를 죽이라 두려워하지 말라 내가 너희에게 명령한 것이 아니냐 너희는 담대히 용기를 내라 한지라\n29. 압살롬의 종들이 압살롬의 명령대로 암논에게 행하매 왕의 모든 아들들이 일어나 각기 노새를 타고 도망하니라'),
  ('2026-03-15', '사무엘하', 12, 13, 17, '13. 다윗이 나단에게 이르되 내가 여호와께 죄를 범하였노라 하매 나단이 다윗에게 말하되 여호와께서도 당신의 죄를 사하셨나니 당신이 죽지 아니하려니와\n14. 이 일로 말미암아 여호와의 원수가 크게 비방할 거리를 얻게 하였으니 당신이 낳은 아이가 반드시 죽으리이다 하고\n15. 나단이 자기 집으로 돌아가니라 우리아의 아내가 다윗에게 낳은 아이를 여호와께서 치시매 심히 앓는지라\n16. 다윗이 그 아이를 위하여 하나님께 간구하되 다윗이 금식하고 안에 들어가서 밤새도록 땅에 엎드렸으니\n17. 그 집의 늙은 자들이 그 곁에 서서 다윗을 땅에서 일으키려 하되 왕이 듣지 아니하고 그들과 더불어 먹지도 아니하더라')
    INSERT INTO public.oq_daily_qt (qt_date, bible_book, chapter, verse_from, verse_to, content)
VALUES
  ('2026-03-16', '사무엘하', 13, 30, 39, '30. 그들이 길에 있을 때에 압살롬이 왕의 모든 아들들을 죽이고 하나도 남기지 아니하였다는 소문이 다윗에게 이르매\n31. 왕이 곧 일어나서 자기의 옷을 찢고 땅에 드러눕고 그의 신하들도 다 옷을 찢고 모셔 선지라\n32. 다윗의 형 시므아의 아들 요나답이 말하여 이르되 내 주여 젊은 왕자들이 다 죽임을 당한 줄로 생각하지 마옵소서 오직 암논만 죽었으리이다 그가 압살롬의 누이 다말을 욕되게 한 날부터 압살롬이 결심한 것이니이다\n33. 그러하온즉 내 주 왕이여 왕자들이 다 죽은 줄로 생각하여 상심하지 마옵소서 오직 암논만 죽었으리이다 하니라\n34. 이에 압살롬은 도망하니라 파수하는 청년이 눈을 들어 보니 뒷산 언덕길로 여러 사람이 오도다\n35. 요나답이 왕에게 아뢰되 보소서 왕자들이 오나이다 당신의 종이 말한 대로 되었나이다 하고\n36. 말을 마치자 왕자들이 이르러 소리를 높여 통곡하니 왕과 그의 모든 신하들도 심히 통곡하니라\n37. 압살롬은 도망하여 그술 왕 암미훌의 아들 달매에게로 갔고 다윗은 날마다 그의 아들로 말미암아 슬퍼하니라\n38. 압살롬이 도망하여 그술로 가서 거기에 산 지 삼 년이라\n39. 다윗 왕의 마음이 압살롬을 향하여 간절하니 암논은 이미 죽었으므로 왕이 위로를 받았음이더라'),
  ('2026-03-17', '사무엘하', 14, 1, 11, '1. 스루야의 아들 요압이 왕의 마음이 압살롬에게로 향하는 줄 알고\n2. 드고아에 사람을 보내 거기서 지혜로운 여인 하나를 데려다가 그에게 이르되 청하건대 너는 상주가 된 것처럼 상복을 입고 기름을 바르지 말고 죽은 사람을 위하여 오래 슬퍼하는 여인 같이 하고\n3. 왕께 들어가서 그에게 이러이러하게 말하라고 요압이 그의 입에 할 말을 넣어 주니라\n4. 드고아 여인이 왕께 아뢸 때에 얼굴을 땅에 대고 엎드려 이르되 왕이여 도우소서 하니\n5. 왕이 그에게 이르되 무슨 일이냐 하니 대답하되 나는 진정 과부니이다 남편은 죽고\n6. 이 여종에게 아들 둘이 있더니 그들이 들에서 싸우나 그들을 말리는 사람이 아무도 없으므로 한 아이가 다른 아이를 쳐죽인지라\n7. 온 족속이 일어나서 당신의 여종 나를 핍박하여 말하기를 그의 동생을 쳐죽인 자를 내놓으라 우리가 그의 동생 죽인 죄를 갚아 그를 죽여 상속자 될 것까지 끊겠노라 하오니 그러한즉 그들이 내게 남아 있는 숯불을 꺼서 내 남편의 이름과 씨를 세상에 남겨 두지 아니하겠나이다 하니\n8. 왕이 여인에게 이르되 네 집으로 가라 내가 너를 위하여 명령을 내리리라 하는지라\n9. 드고아 여인이 왕께 아뢰되 내 주 왕이여 그 죄는 나와 내 아버지의 집으로 돌릴 것이니 왕과 왕위는 허물이 없으리이다\n10. 왕이 이르되 누구든지 네게 말하는 자를 내게로 데려오라 그가 다시는 너를 건드리지도 못하리라 하니라\n11. 여인이 이르되 청하건대 왕은 왕의 하나님 여호와를 기억하사 원수 갚는 자가 더 죽이지 못하게 하옵소서 내 아들을 죽일까 두려워하나이다 하니 왕이 이르되 여호와께서 살아 계심을 두고 맹세하노니 네 아들의 머리카락 하나도 땅에 떨어지지 아니하리라 하니라'),
  ('2026-03-18', '사무엘하', 14, 12, 17, '12. 여인이 이르되 청하건대 당신의 여종을 용납하여 한 말씀을 내 주 왕께 여쭙게 하옵소서 하니 그가 이르되 말하라 하니라\n13. 여인이 이르되 그러면 어찌하여 왕께서 하나님의 백성에게 대하여 이같은 도모를 하셨나이까 이 말씀을 하심으로 왕께서 죄 있는 사람 같이 되심은 그 내쫓긴 자를 왕께서 집으로 돌아오게 하지 아니하심이니이다\n14. 우리는 필경 죽으리니 땅에 쏟아진 물을 다시 담지 못함 같을 것이오나 하나님은 생명을 빼앗지 아니하시고 방책을 베푸사 내쫓긴 자가 하나님께 버린 자가 되지 아니하게 하시나이다\n15. 이제 내가 와서 내 주 왕께 이 말씀을 여쭈옵는 것은 백성들이 나를 두렵게 하므로 당신의 여종이 스스로 말하기를 내가 왕께 여쭈오면 혹시 왕께서 여종이 청하는 것을 시행하실 것이라\n16. 왕께서 들으시고 나와 내 아들을 함께 하나님의 기업에서 끊을 자의 손으로부터 여종을 구원하시리라 함이니이다\n17. 당신의 여종이 또 스스로 말하기를 내 주 왕의 말씀이 내게 위로가 되기를 원한다 하였사오니 이는 내 주 왕께서 하나님의 사자 같이 선과 악을 분간하심이니이다 원하건대 왕의 하나님 여호와께서 왕과 함께 계시옵소서'),
  ('2026-03-19', '사무엘하', 14, 18, 24, '18. 왕이 그 여인에게 대답하여 이르되 바라노니 내가 네게 묻는 것을 내게 숨기지 말라 여인이 이르되 내 주 왕은 말씀하옵소서\n19. 왕이 이르되 이 모든 일에 요압이 너와 함께 하였느냐 하니 여인이 대답하여 이르되 내 주 왕의 살아 계심을 두고 맹세하옵나니 내 주 왕의 말씀을 좌로나 우로나 옮길 자가 없으리이다 왕의 종 요압이 내게 명령하였고 그가 이 모든 말을 당신의 여종의 입에 넣어 주었사오니\n20. 이는 왕의 종 요압이 이 일의 형편을 바꾸려 하여 이렇게 함이니이다 내 주 왕의 지혜는 하나님의 사자의 지혜와 같아서 땅에 있는 일을 다 아시나이다 하니라\n21. 왕이 요압에게 이르되 내가 이 일을 허락하였으니 가서 청년 압살롬을 데려오라 하니라\n22. 요압이 땅에 엎드려 절하고 왕을 위하여 복을 빌고 요압이 이르되 내 주 왕이여 종의 구함을 왕이 허락하시니 종이 왕 앞에서 은혜 입은 줄을 오늘 아나이다 하고\n23. 요압이 일어나 그술로 가서 압살롬을 데리고 예루살렘으로 오니\n24. 왕이 이르되 그를 그의 집으로 물러가게 하여 내 얼굴을 볼 수 없게 하라 하매 압살롬이 자기 집으로 물러가고 왕의 얼굴을 보지 못하니라'),
  ('2026-03-20', '사무엘하', 14, 25, 33, '25. 온 이스라엘 가운데에서 압살롬 같이 아름다움으로 크게 칭찬받는 자가 없었으니 그는 발바닥부터 정수리까지 흠이 없음이라\n26. 그의 머리털이 무거우므로 연말마다 깎았으며 그 머리털을 깎을 때에 그것을 달아 본즉 그의 머리털이 왕의 저울로 이백 세겔이었더라\n27. 압살롬이 아들 셋과 딸 하나를 낳았는데 딸의 이름은 다말이라 그는 얼굴이 아름다운 여인이더라\n28. 압살롬이 이 년 동안 예루살렘에 있으되 왕의 얼굴을 보지 못하였으므로\n29. 압살롬이 요압을 왕께 보내려 하여 압살롬이 요압에게 사람을 보내 부르되 그에게 오지 아니하고 또 다시 그에게 보내되 오지 아니하는지라\n30. 압살롬이 자기 종들에게 이르되 보라 요압의 밭이 내 밭 근처에 있고 거기 보리가 있으니 가서 불을 놓으라 하니라 압살롬의 종들이 그 밭에 불을 놓았더니\n31. 요압이 일어나 압살롬의 집으로 가서 그에게 이르되 어찌하여 네 종들이 내 밭에 불을 놓았느냐 하니\n32. 압살롬이 요압에게 대답하되 내가 일찍이 사람을 네게 보내 너를 이리로 오라고 청한 것은 내가 너를 왕께 보내 아뢰게 하기를 어찌하여 내가 그술에서 돌아오게 되었나이까 이때까지 거기 있는 것이 내게 나았으리이다 하려 함이로라 이제는 네가 나로 하여금 왕의 얼굴을 보게 하라 내가 만일 죄가 있으면 왕이 나를 죽이시는 것이 옳으니라 하는지라\n33. 요압이 왕에게 나아가서 그에게 아뢰매 왕이 압살롬을 부르니 그가 왕께 나아가 그 앞에서 얼굴을 땅에 대어 그에게 절하매 왕이 압살롬과 입을 맞추니라'),
  ('2026-03-21', '사무엘하', 15, 1, 6, '1. 그 후에 압살롬이 자기를 위하여 병거와 말들을 준비하고 호위병 오십 명을 그 앞에 세우니라\n2. 압살롬이 일찍이 일어나 성문 길 곁에 서서 어떤 사람이든지 송사가 있어 왕에게 재판을 청하러 올 때에 그 사람을 불러 이르되 너는 어느 성읍 사람이냐 하니 그 사람의 대답이 종은 이스라엘 아무 지파에 속하였나이다 하면\n3. 압살롬이 그에게 이르기를 보라 네 일이 옳고 바르다마는 네 송사를 들을 사람을 왕께서 세우지 아니하셨다 하고\n4. 또 압살롬이 이르기를 내가 이 땅에서 재판관이 되고 누구든지 송사나 재판할 일이 있어 내게로 오는 자에게 내가 정의 베풀기를 원하노라 하고\n5. 사람이 가까이 와서 그에게 절하려 하면 압살롬이 손을 펴서 그 사람을 붙들고 그에게 입을 맞추니\n6. 이스라엘 무리 중에 왕에게 재판을 청하러 오는 자들마다 압살롬의 행함이 이같아서 이스라엘 사람의 마음을 압살롬이 훔치니라'),
  ('2026-03-22', '사무엘하', 14, 12, 17, '12. 여인이 이르되 청하건대 당신의 여종을 용납하여 한 말씀을 내 주 왕께 여쭙게 하옵소서 하니 그가 이르되 말하라 하니라\n13. 여인이 이르되 그러면 어찌하여 왕께서 하나님의 백성에게 대하여 이같은 도모를 하셨나이까 이 말씀을 하심으로 왕께서 죄 있는 사람 같이 되심은 그 내쫓긴 자를 왕께서 집으로 돌아오게 하지 아니하심이니이다\n14. 우리는 필경 죽으리니 땅에 쏟아진 물을 다시 담지 못함 같을 것이오나 하나님은 생명을 빼앗지 아니하시고 방책을 베푸사 내쫓긴 자가 하나님께 버린 자가 되지 아니하게 하시나이다\n15. 이제 내가 와서 내 주 왕께 이 말씀을 여쭈옵는 것은 백성들이 나를 두렵게 하므로 당신의 여종이 스스로 말하기를 내가 왕께 여쭈오면 혹시 왕께서 여종이 청하는 것을 시행하실 것이라\n16. 왕께서 들으시고 나와 내 아들을 함께 하나님의 기업에서 끊을 자의 손으로부터 여종을 구원하시리라 함이니이다\n17. 당신의 여종이 또 스스로 말하기를 내 주 왕의 말씀이 내게 위로가 되기를 원한다 하였사오니 이는 내 주 왕께서 하나님의 사자 같이 선과 악을 분간하심이니이다 원하건대 왕의 하나님 여호와께서 왕과 함께 계시옵소서'),
  ('2026-03-23', '사무엘하', 15, 7, 12, '7. 사 년 만에 압살롬이 왕께 아뢰되 내가 여호와께 서원한 것이 있사오니 청건대 내가 헤브론에 가서 그 서원을 이루게 하소서\n8. 당신의 종이 아람 그술에 있을 때에 서원하기를 만일 여호와께서 반드시 나를 예루살렘으로 돌아가게 하시면 내가 여호와를 섬기리이다 하였나이다\n9. 왕이 그에게 이르되 평안히 가라 하니 그가 일어나 헤브론으로 가니라\n10. 이에 압살롬이 정탐을 이스라엘 모든 지파 가운데에 두루 보내 이르기를 너희는 나팔 소리를 듣거든 곧 말하기를 압살롬이 헤브론에서 왕이 되었다 하라 하니라\n11. 그때 압살롬에게 청함을 받은 이백 명이 예루살렘에서부터 그와 함께 갔으니 그들은 그 사정을 알지 못하고 그저 따라가기만 한 사람들이라\n12. 제사 드릴 때에 압살롬이 사람을 보내 다윗의 모사 길로 사람 아히도벨을 그의 성읍 길로에서 청하여 온지라 반역하는 일이 커가매 압살롬에게로 돌아오는 백성이 많아지니라'),
  ('2026-03-24', '사무엘하', 15, 13, 23, '13. 전령이 다윗에게 와서 말하되 이스라엘의 인심이 다 압살롬에게로 돌아갔나이다 한지라\n14. 다윗이 예루살렘에 함께 있는 그의 모든 신하들에게 이르되 일어나 도망하자 그렇지 아니하면 우리 중 한 사람도 압살롬에게서 피하지 못하리라 빨리 가자 두렵건대 그가 우리를 급히 따라와 우리를 해하고 칼날로 성읍을 칠까 하노라\n15. 왕의 신하들이 왕께 아뢰되 우리 주 왕께서 경영하시는 대로 우리가 준행하리이다 보소서 당신의 종들이니이다 하더라\n16. 왕이 나갈 때에 그의 가족을 다 따르게 하고 후궁 열 명을 왕이 남겨 두어 왕궁을 지키게 하니라\n17. 왕이 나가매 모든 백성이 다 따라서 메르학에 이르러 멈추어 서니\n18. 그의 모든 부하들이 그의 곁으로 지나가고 모든 그렛 사람과 모든 블렛 사람과 및 왕을 따라 가드에서 온 모든 가드 사람 육백 명이 왕 앞에서 행진하니라\n19. 그때에 왕이 가드 사람 잇대에게 이르되 어찌하여 너도 우리와 함께 가느냐 너는 쫓겨난 외국인이니 돌아가서 왕과 함께 네 곳에 있으라\n20. 너는 어제 왔고 나는 정처 없이 가니 오늘 어찌 너를 우리와 함께 떠돌게 하리요 너도 돌아가고 네 동포들도 데려가라 은혜와 진리가 너와 함께 있기를 원하노라 하니라\n21. 잇대가 왕께 대답하여 이르되 여호와의 살아 계심과 내 주 왕의 살아 계심으로 맹세하옵나니 진실로 내 주 왕께서 어느 곳에 계시든지 사나 죽으나 종도 그 곳에 있겠나이다 하니\n22. 다윗이 잇대에게 이르되 앞서 건너가라 하매 가드 사람 잇대와 그의 수행자들과 그와 함께 한 아이들이 다 건너가고\n23. 온 땅 사람이 큰 소리로 울며 모든 백성이 앞서 건너가매 왕도 기드론 시내를 건너가니 건너간 모든 백성이 광야 길로 향하니라'),
  ('2026-03-25', '사무엘하', 15, 24, 29, '24. 보라 사독과 그와 함께 한 모든 레위 사람도 하나님의 언약궤를 메어다가 하나님의 궤를 내려놓고 아비아달도 올라와서 모든 백성이 성에서 나오기를 기다리도다\n25. 왕이 사독에게 이르되 보라 하나님의 궤를 성읍으로 도로 메어 가라 만일 내가 여호와 앞에서 은혜를 입으면 도로 나를 인도하사 내게 그 궤와 그 계신 데를 보이시리라\n26. 그러나 그가 이와 같이 말씀하시기를 내가 너를 기뻐하지 아니한다 하시면 종이 여기 있사오니 선히 여기시는 대로 내게 행하시옵소서 하리라\n27. 왕이 또 제사장 사독에게 이르되 네가 선견자가 아니냐 너는 너희의 두 아들 곧 네 아들 아히마아스와 아비아달의 아들 요나단을 데리고 평안히 성읍으로 돌아가라\n28. 너희에게서 내게 알리는 소식이 올 때까지 내가 광야 나루터에서 기다리리라 하니라\n29. 사독과 아비아달이 하나님의 궤를 예루살렘으로 도로 메어다 놓고 거기 머물러 있으니라'),
  ('2026-03-26', '사무엘하', 15, 30, 37, '30. 다윗이 감람 산길로 올라갈 때에 그의 머리를 그가 가리고 맨발로 울며 올라가며 그와 함께 가는 모든 백성들도 각기 자기의 머리를 가리고 울며 올라가니라\n31. 어떤 사람이 다윗에게 알리되 압살롬과 함께 반역한 자들 가운데 아히도벨이 있나이다 하니 다윗이 이르되 여호와여 원하옵건대 아히도벨의 모략을 어리석게 하옵소서 하니라\n32. 다윗이 하나님을 경배하는 마루턱에 이를 때에 아렉 사람 후새가 옷을 찢고 흙을 머리에 뒤집어쓰고 다윗을 맞으러 온지라\n33. 다윗이 그에게 이르되 네가 만일 나와 함께 가면 내게 짐이 되리라\n34. 그러나 네가 만일 성읍으로 돌아가서 압살롬에게 말하기를 왕이여 내가 왕의 종이니이다 전에는 왕의 아버지의 종이었더니 이제는 왕의 종이니이다 하면 네가 나를 위하여 아히도벨의 모략을 패하게 하리라\n35. 사독과 아비아달 두 제사장이 너와 함께 거기 있지 아니하냐 네가 왕의 궁중에서 무엇을 듣든지 사독과 아비아달 두 제사장에게 알리라\n36. 그들의 두 아들 곧 사독의 아히마아스와 아비아달의 요나단이 그들과 함께 거기 있나니 너희가 듣는 모든 것을 그들 편에 내게 보낼지니라 하는지라\n37. 다윗의 친구 후새가 곧 성읍으로 들어가고 압살롬도 예루살렘으로 들어갔더라'),
  ('2026-03-27', '사무엘하', 16, 1, 14, '1. 다윗이 마루턱을 조금 지나니 므비보셋의 사환 시바가 안장 지운 두 나귀에 떡 이백 개와 건포도 백 송이와 여름 과일 백 개와 포도주 한 가죽부대를 싣고 다윗을 맞는지라\n2. 왕이 시바에게 이르되 네가 무슨 뜻으로 이것을 가져왔느냐 하니 시바가 이르되 나귀는 왕의 가족들이 타게 하고 떡과 과일은 청년들이 먹게 하고 포도주는 들에서 피곤한 자들에게 마시게 하려 함이니이다\n3. 왕이 이르되 네 주인의 아들이 어디 있느냐 하니 시바가 왕께 아뢰되 예루살렘에 있는데 그가 말하기를 이스라엘 족속이 오늘 내 아버지의 나라를 내게 돌리리라 하나이다 하는지라\n4. 왕이 시바에게 이르되 므비보셋에게 있는 것이 다 네 것이니라 하니 시바가 이르되 내가 절하나이다 내 주 왕이여 내가 왕 앞에서 은혜를 입게 하옵소서 하니라\n5. 다윗 왕이 바후림에 이르매 거기서 사울의 친족 한 사람이 나오니 게라의 아들이요 이름은 시무이라 그가 나오면서 계속하여 저주하고\n6. 또 다윗과 다윗 왕의 모든 신하들을 향하여 돌을 던지니 그때에 모든 백성과 용사들은 다 왕의 좌우에 있었더라\n7. 시무이가 저주하는 가운데 이와 같이 말하니라 피를 흘린 자여 사악한 자여 가거라 가거라\n8. 사울의 족속의 모든 피를 여호와께서 네게로 돌리셨도다 그를 대신하여 네가 왕이 되었으나 여호와께서 나라를 네 아들 압살롬의 손에 넘기셨도다 보라 너는 피를 흘린 자이므로 화를 자초하였느니라 하는지라\n9. 스루야의 아들 아비새가 왕께 여짜오되 이 죽은 개가 어찌 내 주 왕을 저주하리이까 청하건대 내가 건너가서 그의 머리를 베게 하소서 하니\n10. 왕이 이르되 스루야의 아들들아 내가 너희와 무슨 상관이 있느냐 그가 저주하는 것은 여호와께서 그에게 다윗을 저주하라 하심이니 네가 어찌 그리하였느냐 할 자가 누구겠느냐 하고\n11. 또 다윗이 아비새와 모든 신하들에게 이르되 내 몸에서 난 아들도 내 생명을 해하려 하거든 하물며 이 베냐민 사람이랴 여호와께서 그에게 명령하신 것이니 그가 저주하게 버려두라\n12. 혹시 여호와께서 나의 원통함을 감찰하시리니 오늘 그 저주 때문에 여호와께서 선으로 내게 갚아 주시리라 하고\n13. 다윗과 그의 추종자들이 길을 갈 때에 시무이는 산비탈로 타고 가면서 저주하고 그를 향하여 돌을 던지며 먼지를 날리더라\n14. 왕과 그와 함께 있는 백성들이 다 피곤하여 한 곳에 이르러 거기서 쉬니라'),
  ('2026-03-28', '사무엘하', 16, 15, 23, '15. 압살롬과 모든 이스라엘 백성들이 예루살렘에 이르고 아히도벨도 그와 함께 이른지라\n16. 다윗의 친구 아렉 사람 후새가 압살롬에게 나갈 때에 압살롬에게 말하기를 왕이여 만세, 왕이여 만세 하니\n17. 압살롬이 후새에게 이르되 이것이 네가 친구를 후대하는 것이냐 네가 어찌하여 네 친구와 함께 가지 아니하였느냐 하니\n18. 후새가 압살롬에게 이르되 그렇지 아니하니이다 내가 여호와와 이 백성 모든 이스라엘의 택한 자에게 속하여 그와 함께 있을 것이니이다\n19. 또 내가 이제 누구를 섬기리이까 그의 아들이 아니니이까 내가 전에 왕의 아버지를 섬긴 것 같이 왕을 섬기리이다 하니라\n20. 압살롬이 아히도벨에게 이르되 너는 어떻게 행할 계략을 우리에게 가르치라 하니\n21. 아히도벨이 압살롬에게 이르되 왕의 아버지가 남겨 두어 왕궁을 지키게 한 후궁들과 더불어 동침하소서 그리하면 왕께서 왕의 아버지가 미워하는 바 됨을 온 이스라엘이 들으리니 왕과 함께 있는 모든 사람의 힘이 더욱 강하여지리이다 하니라\n22. 이에 사람들이 압살롬을 위하여 옥상에 장막을 치니 압살롬이 온 이스라엘 무리의 눈앞에서 그 아버지의 후궁들과 더불어 동침하니라\n23. 그때에 아히도벨이 베푸는 계략은 사람이 하나님께 물어서 받은 말씀과 같은 것이라 아히도벨의 모든 계략은 다윗에게나 압살롬에게나 그와 같이 여겨졌더라'),
  ('2026-03-29', '사무엘하', 16, 5, 12, '5. 다윗 왕이 바후림에 이르매 거기서 사울의 친족 한 사람이 나오니 게라의 아들이요 이름은 시무이라 그가 나오면서 계속하여 저주하고\n6. 또 다윗과 다윗 왕의 모든 신하들을 향하여 돌을 던지니 그때에 모든 백성과 용사들은 다 왕의 좌우에 있었더라\n7. 시무이가 저주하는 가운데 이와 같이 말하니라 피를 흘린 자여 사악한 자여 가거라 가거라\n8. 사울의 족속의 모든 피를 여호와께서 네게로 돌리셨도다 그를 대신하여 네가 왕이 되었으나 여호와께서 나라를 네 아들 압살롬의 손에 넘기셨도다 보라 너는 피를 흘린 자이므로 화를 자초하였느니라 하는지라\n9. 스루야의 아들 아비새가 왕께 여짜오되 이 죽은 개가 어찌 내 주 왕을 저주하리이까 청하건대 내가 건너가서 그의 머리를 베게 하소서 하니\n10. 왕이 이르되 스루야의 아들들아 내가 너희와 무슨 상관이 있느냐 그가 저주하는 것은 여호와께서 그에게 다윗을 저주하라 하심이니 네가 어찌 그리하였느냐 할 자가 누구겠느냐 하고\n11. 또 다윗이 아비새와 모든 신하들에게 이르되 내 몸에서 난 아들도 내 생명을 해하려 하거든 하물며 이 베냐민 사람이랴 여호와께서 그에게 명령하신 것이니 그가 저주하게 버려두라\n12. 혹시 여호와께서 나의 원통함을 감찰하시리니 오늘 그 저주 때문에 여호와께서 선으로 내게 갚아 주시리라 하고'),
  ('2026-03-30', '마태복음', 26, 69, 75, '69. 베드로가 바깥 뜰에 앉았더니 한 여종이 나아와 이르되 너도 갈릴리 사람 예수와 함께 있었도다 하거늘\n70. 베드로가 모든 사람 앞에서 부인하여 이르되 나는 네가 무슨 말을 하는지 알지 못하겠노라 하며\n71. 앞문까지 나아가니 다른 여종이 그를 보고 거기 있는 사람들에게 말하되 이 사람은 나사렛 예수와 함께 있었도다 하매\n72. 베드로가 맹세하고 또 부인하여 이르되 나는 그 사람을 알지 못하노라 하더라\n73. 조금 후에 곁에 섰던 사람들이 나아와 베드로에게 이르되 너도 진실로 그 당이라 네 말소리가 너를 표명한다 하거늘\n74. 그가 저주하며 맹세하여 이르되 나는 그 사람을 알지 못하노라 하니 곧 닭이 울더라\n75. 이에 베드로가 예수의 말씀에 닭 울기 전에 네가 세 번 나를 부인하리라 하심이 생각나서 밖에 나가서 심히 통곡하니라'),
  ('2026-03-31', '마태복음', 27, 1, 10, '1. 새벽에 모든 대제사장과 백성의 장로들이 예수를 죽이려고 함께 의논하고\n2. 결박하여 끌고 가서 총독 빌라도에게 넘겨 주니라\n3. 그때에 예수를 판 유다가 그의 정죄됨을 보고 스스로 뉘우쳐 그 은 삼십을 대제사장들과 장로들에게 도로 갖다 주며\n4. 이르되 내가 무죄한 피를 팔고 죄를 범하였도다 하니 그들이 이르되 그것이 우리에게 무슨 상관이냐 네가 당하라 하거늘\n5. 유다가 은을 성소에 던져 넣고 물러가서 스스로 목 매어 죽은지라\n6. 대제사장들이 그 은을 거두며 이르되 이것은 핏값이라 성전고에 넣어 둠이 옳지 않다 하고\n7. 의논한 후 이것으로 토기장이의 밭을 사서 나그네의 묘지를 삼았으니\n8. 그러므로 오늘날까지 그 밭을 피밭이라 일컫느니라\n9. 이에 선지자 예레미야를 통하여 하신 말씀이 이루어졌나니 일렀으되 그들이 그 가격 매겨진 자 곧 이스라엘 자손 중에서 가격 매긴 자의 가격인 은 삼십을 가지고\n10. 토기장이의 밭 값으로 주었으니 이는 주께서 내게 명하신 바와 같으니라 하였더라')
